import{_ as t,c as e,o as r,a4 as a}from"./chunks/framework.HaEZziQ1.js";const _=JSON.parse('{"title":"CSS重点","description":"","frontmatter":{},"headers":[],"relativePath":"Document/前端面试相关/CSS和HTML面试题/CSS重点记忆.md","filePath":"Document/前端面试相关/CSS和HTML面试题/CSS重点记忆.md","lastUpdated":1709668918000}'),l={name:"Document/前端面试相关/CSS和HTML面试题/CSS重点记忆.md"},s=a('<h1 id="css重点" tabindex="-1">CSS重点 <a class="header-anchor" href="#css重点" aria-label="Permalink to &quot;CSS重点&quot;">​</a></h1><p><strong>postion</strong></p><ul><li><a href="https://link.zhihu.com/?target=https%3A//www.zhangxinxu.com/wordpress/2018/12/css-position-sticky/" target="_blank" rel="noreferrer">杀了个回马枪，还是说说position:sticky吧</a></li></ul><p><strong>flex</strong></p><p>布局的传统解决方案，基于盒状模型，依赖 display属性 + position属性 + float属性。它对于那些特殊布局非常不方便，比如，垂直居中就不容易实现。但flex两行代码就可以实现</p><ul><li><a href="https://link.zhihu.com/?target=https%3A//www.runoob.com/w3cnote/flex-grammar.html" target="_blank" rel="noreferrer">Flex 布局语法教程</a></li><li><a href="https://link.zhihu.com/?target=https%3A//www.cnblogs.com/qcloud1001/p/9848619.html" target="_blank" rel="noreferrer">30分钟彻底弄懂flex布局</a></li></ul><p><strong>页面布局</strong></p><ul><li><a href="https://link.zhihu.com/?target=https%3A//juejin.im/post/5b9a4477f265da0ad82bf921%23heading-9" target="_blank" rel="noreferrer">CSS实现水平垂直居中的1010种方式</a></li><li><a href="https://link.zhihu.com/?target=https%3A//juejin.im/post/599970f4518825243a78b9d5" target="_blank" rel="noreferrer">CSS 常见布局方式</a></li><li><a href="https://link.zhihu.com/?target=https%3A//juejin.im/post/5aa252ac518825558001d5de" target="_blank" rel="noreferrer">各种常见布局实现+知名网站实例分析</a></li></ul><p><strong>css盒模型</strong></p><p>在最初接触CSS的时候，对于CSS盒模型的不了解，撞了很多次的南墙呀。盒模型是网页布局的基础，它制定了元素如何在页面中显示，如果足够地掌握，那使用CSS布局那将会容易得多。</p><ul><li><a href="https://link.zhihu.com/?target=https%3A//www.cnblogs.com/ylliap/p/6119740.html" target="_blank" rel="noreferrer">css盒模型全面解析</a></li></ul><p><strong>h5适配各种设备</strong></p><ul><li><a href="https://link.zhihu.com/?target=https%3A//blog.csdn.net/a460550542/article/details/79765164" target="_blank" rel="noreferrer">从淘宝和网易的font-size思考移动端怎样使用rem？</a></li><li><a href="https://link.zhihu.com/?target=https%3A//cloud.tencent.com/developer/article/1352187" target="_blank" rel="noreferrer">细说移动端 经典的REM布局 与 新秀VW布局</a></li></ul><p><strong>BFC</strong></p><p>BFC是块级格式化上下文，是一个独立的渲染区域，让处于 BFC 内部的元素与外部的元素相互隔离，使内外元素的定位不会相互影响</p><ul><li><a href="https://link.zhihu.com/?target=https%3A//blog.csdn.net/sinat_36422236/article/details/88763187" target="_blank" rel="noreferrer">什么是BFC？看这一篇就够了</a></li></ul><p><strong>CSS3动画</strong></p><p>在 CSS3 出现之前，动画都是通过 JavaScript 动态的改变元素的样式属性来完成了，这种方式虽然能够实现动画，但是在性能上存在一些问题。CSS3 的出现，让动画变得更加容易，性能也更加好。</p><ul><li><a href="https://link.zhihu.com/?target=https%3A//www.jianshu.com/p/15f2adfbdad0" target="_blank" rel="noreferrer">css3动画详解</a></li><li><a href="https://link.zhihu.com/?target=https%3A//www.jianshu.com/p/7bfd8764ffc2" target="_blank" rel="noreferrer">前端面试题——如何画一条0.5px的线</a></li></ul><p><strong>CSS 预处理器</strong></p><p>less和sass大家肯定都用过，今天我们从另一个角度来谈谈他们</p><ul><li><a href="https://link.zhihu.com/?target=https%3A//aotu.io/notes/2019/10/29/css-preprocessor/index.html" target="_blank" rel="noreferrer">2019年，你是否可以抛弃 CSS 预处理器？</a></li></ul><p><strong>移动端的问题</strong></p><p>移动端web项目越来越多，设计师对于UI的要求也越来越高，比如1px 的边框。在<code>高清屏</code>下，移动端的1px 会很粗</p><ul><li><a href="https://link.zhihu.com/?target=https%3A//juejin.im/post/5d19b729f265da1bb2774865" target="_blank" rel="noreferrer">移动端1px解决方案</a></li></ul><p>在写h5页面时，页面滚动一定是让开发者头痛的一部分。特别是当页面布局嵌套较深，子元素各种脱离文档流，我们在获取元素距离值、控制滚动条时各种出错。明明代码没有问题，但展现的效果就是和想象的不一样。此时是不是觉得css很诡异。其实不然，css也是有自己逻辑的，只是你了解的还不够深入，今天带大家全面解析页面滚动。</p><ul><li><a href="https://zhuanlan.zhihu.com/p/89097187" target="_blank" rel="noreferrer">页面滑动和定位全面解析</a></li></ul>',27),o=[s];function n(i,p,h,c,u,g){return r(),e("div",null,o)}const m=t(l,[["render",n]]);export{_ as __pageData,m as default};
